<template>
  <div>
    <el-card>
      <div slot="header">我的课程表</div>
      <el-table :data="list" border stripe v-loading="loading">
        <el-table-column prop="courseName" label="课程" />
        <el-table-column prop="teacherName" label="教师" />
        <el-table-column prop="bookingTime" label="上课时间" width="160" />
        <el-table-column prop="status" label="状态" width="80">
          <template slot-scope="scope">
            <el-tag :type="scope.row.status===1?'success':'warning'" size="small">
              {{ scope.row.status===1?'已确认':'待确认' }}
            </el-tag>
          </template>
        </el-table-column>
        <el-table-column prop="remark" label="备注" show-overflow-tooltip />
      </el-table>
    </el-card>
  </div>
</template>
<script>
import request from '@/utils/request'
export default {
  data() { return { list: [], loading: false } },
  created() { this.loadData() },
  methods: {
    loadData() {
      this.loading = true
      const user = JSON.parse(sessionStorage.getItem('loginUser') || '{}')
      request.get('/api/booking', { params: { pageNum: 1, pageSize: 999, studentId: user.id, status: 1 } }).then(res => {
        this.list = res.data.records || []
      }).finally(() => { this.loading = false })
    }
  }
}
</script>
